import React from 'react';

const estadoConfig = {
  nuevo:      { label:'Nuevo',          color:'#F59E0B', bg:'#FEF3C7', siguiente:'preparacion' },
  preparacion:{ label:'En preparación', color:'#3B82F6', bg:'#DBEAFE', siguiente:'listo'       },
  listo:      { label:'Listo',          color:'#10B981', bg:'#D1FAE5', siguiente:'entregado'   },
  entregado:  { label:'Entregado',      color:'#6B7280', bg:'#F3F4F6', siguiente:null          },
};

export default function ModalPedido({ pedido, onClose, onCambiarEstado }) {
  if (!pedido) return null;

  const cfg = estadoConfig[pedido.estado] || estadoConfig.nuevo;
  const pasos = ['nuevo','preparacion','listo','entregado'];
  const delivery = 15;

  let productos = [];
  try {
    productos = Array.isArray(pedido.productos) ? pedido.productos : JSON.parse(pedido.productos || '[]');
  } catch(e) { productos = []; }

  const subtotal = productos.reduce((s,x)=>s+(x.cant||x.cantidad||1)*x.precio,0);

  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.45)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000 }}
      onClick={e=>{ if(e.target===e.currentTarget) onClose(); }}>
      <div style={{ background:'#fff', borderRadius:16, width:'100%', maxWidth:480, margin:'1rem', maxHeight:'90vh', overflowY:'auto' }}>
        <div style={{ padding:'1.25rem', borderBottom:'1px solid #F1F5F9', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div>
            <div style={{ fontWeight:700, fontSize:16 }}>Detalle del pedido</div>
            <div style={{ fontSize:12, color:'#94A3B8' }}>{new Date(pedido.created_at).toLocaleString('es-BO')}</div>
          </div>
          <button onClick={onClose} style={{ border:'none', background:'#F1F5F9', borderRadius:8, padding:'6px 10px', cursor:'pointer', fontSize:16 }}>✕</button>
        </div>

        <div style={{ padding:'1.25rem' }}>
          <div style={{ background:'#F8FAFC', borderRadius:10, padding:'1rem', marginBottom:'1rem' }}>
            <div style={{ fontWeight:600, fontSize:13, marginBottom:8, color:'#64748B' }}>CLIENTE</div>
            <div style={{ fontWeight:500, fontSize:15 }}>{pedido.cliente_nombre}</div>
            {pedido.cliente_telefono && <div style={{ fontSize:13, color:'#64748B', marginTop:2 }}>📞 {pedido.cliente_telefono}</div>}
            {pedido.cliente_direccion && <div style={{ fontSize:13, color:'#64748B', marginTop:2 }}>📍 {pedido.cliente_direccion}</div>}
          </div>

          {productos.length > 0 && (
            <div style={{ marginBottom:'1rem' }}>
              <div style={{ fontWeight:600, fontSize:13, marginBottom:8, color:'#64748B' }}>PRODUCTOS</div>
              {productos.map((p,i) => (
                <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', borderBottom:'1px solid #F1F5F9', fontSize:14 }}>
                  <span>{(p.cant||p.cantidad||1)}x {p.nombre}</span>
                  <span style={{ fontWeight:500 }}>Bs. {(p.cant||p.cantidad||1)*p.precio}</span>
                </div>
              ))}
              <div style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', fontSize:13, color:'#94A3B8' }}>
                <span>Subtotal</span><span>Bs. {subtotal}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', padding:'6px 0', fontSize:13, color:'#94A3B8' }}>
                <span>Delivery</span><span>Bs. {delivery}</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', padding:'8px 0', fontWeight:700, fontSize:15, borderTop:'2px solid #1E293B', marginTop:4 }}>
                <span>Total</span><span>Bs. {Number(pedido.total||subtotal+delivery).toFixed(0)}</span>
              </div>
            </div>
          )}

          <div style={{ marginBottom:'1.25rem' }}>
            <div style={{ fontWeight:600, fontSize:13, marginBottom:10, color:'#64748B' }}>ESTADO</div>
            <div style={{ display:'flex', gap:6 }}>
              {pasos.map((paso,i) => {
                const c = estadoConfig[paso];
                const activo = pasos.indexOf(pedido.estado) >= i;
                return (
                  <div key={paso} style={{ flex:1, textAlign:'center' }}>
                    <div style={{ width:28, height:28, borderRadius:'50%', background: activo ? c.color : '#E2E8F0', margin:'0 auto 4px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:12, color:'#fff', fontWeight:700 }}>{i+1}</div>
                    <div style={{ fontSize:10, color: activo ? c.color : '#94A3B8', fontWeight: activo?600:400 }}>{c.label}</div>
                  </div>
                );
              })}
            </div>
          </div>

          <div style={{ display:'flex', gap:8 }}>
            {cfg.siguiente && (
              <button onClick={()=>{ onCambiarEstado(pedido.id, cfg.siguiente); onClose(); }}
                style={{ flex:1, padding:'10px', borderRadius:8, border:'none', background:'#2563EB', color:'#fff', fontWeight:600, cursor:'pointer', fontSize:14 }}>
                Pasar a: {estadoConfig[cfg.siguiente].label}
              </button>
            )}
            <button onClick={()=>window.print()}
              style={{ padding:'10px 14px', borderRadius:8, border:'1px solid #E2E8F0', background:'transparent', cursor:'pointer', fontSize:14 }}>
              🖨 Imprimir
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
